## Why Asked
Interviewers ask this to assess your understanding of DevOps fundamentals and automation tools that are critical in modern software development pipelines.

## Key Concepts
- Jenkins as automation server
- CI/CD pipeline automation
- Plugin ecosystem
- Distributed builds
- Integration with version control

## Code Example
```groovy
// Jenkinsfile - Declarative Pipeline
pipeline {
    agent any

    environment {
        DOCKER_REGISTRY = 'mycompany.azurecr.io'
        IMAGE_TAG = "${env.BUILD_NUMBER}-${env.GIT_COMMIT.take(8)}"
    }

    triggers {
        pollSCM('H/5 * * * *') // Poll every 5 minutes
    }

    stages {
        stage('Checkout') {
            steps {
                git branch: 'main', url: 'https://github.com/company/app.git'
            }
        }

        stage('Build & Test') {
            parallel {
                stage('Unit Tests') {
                    steps {
                        sh 'npm ci && npm run test:unit'
                        junit 'test-results.xml'
                    }
                }
                stage('Integration Tests') {
                    steps {
                        sh 'npm run test:integration'
                        publishHTML([allowMissing: false, alwaysLinkToLastBuild: true, 
                                    keepAll: true, reportDir: 'coverage', 
                                    reportFiles: 'index.html', reportName: 'Coverage Report'])
                    }
                }
            }
        }

        stage('Security Scan') {
            steps {
                sh 'npm audit --audit-level high'
                sh 'sonar-scanner -Dsonar.projectKey=myapp'
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    def image = docker.build("${DOCKER_REGISTRY}/myapp:${IMAGE_TAG}")
                    image.push()
                    image.push('latest')
                }
            }
        }

        stage('Deploy to Staging') {
            when {
                branch 'main'
            }
            steps {
                withCredentials([kubeconfigFile(credentialsId: 'k8s-staging', variable: 'KUBECONFIG')]) {
                    sh 'helm upgrade --install myapp ./helm-chart --namespace staging --set image.tag=${IMAGE_TAG}'
                }
            }
        }

        stage('Deploy to Production') {
            when {
                branch 'main'
                expression { 
                    return currentBuild.result == null || currentBuild.result == 'SUCCESS'
                }
            }
            input {
                message "Deploy to production?"
                ok "Deploy"
            }
            steps {
                withCredentials([kubeconfigFile(credentialsId: 'k8s-prod', variable: 'KUBECONFIG')]) {
                    sh 'helm upgrade --install myapp ./helm-chart --namespace production --set image.tag=${IMAGE_TAG}'
                    slackSend(color: 'good', message: "✅ Deployed version ${IMAGE_TAG} to production")
                }
            }
        }
    }

    post {
        always {
            cleanWs()
        }
        success {
            emailext(
                subject: "✅ Build Success: ${env.JOB_NAME} - ${env.BUILD_NUMBER}",
                body: "Build succeeded. View details: ${env.BUILD_URL}",
                to: 'dev-team@company.com'
            )
        }
        failure {
            emailext(
                subject: "❌ Build Failed: ${env.JOB_NAME} - ${env.BUILD_NUMBER}",
                body: "Build failed. View details: ${env.BUILD_URL}",
                to: 'dev-team@company.com'
            )
        }
    }
}
```

