// Pseudo-policy check (OPA-like)
function validatePolicy(manifest) {
  const {sbom, signatures, images, gates} = manifest;
  if (!signatures.includes(images.sign)) return false;
  return sbom.version === '1.0' && gates.canary;
}
```

